import{_ as n,o as s,c as e,S as t}from"./chunks/framework.C6RQlTYc.js";const u=JSON.parse('{"title":"面试官问：预训练和微调的区别？什么是 LoRA？","description":"","frontmatter":{},"headers":[],"relativePath":"面试官问/17ai/q_ai_9-pretraining_finetuning.md","filePath":"面试官问/17ai/q_ai_9-pretraining_finetuning.md","lastUpdated":1778207238000}'),i={name:"面试官问/17ai/q_ai_9-pretraining_finetuning.md"};function l(r,a,p,o,d,c){return s(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="面试官问-预训练和微调的区别-什么是-lora" tabindex="-1">面试官问：预训练和微调的区别？什么是 LoRA？ <a class="header-anchor" href="#面试官问-预训练和微调的区别-什么是-lora" aria-label="Permalink to &quot;面试官问：预训练和微调的区别？什么是 LoRA？&quot;">​</a></h1><blockquote><p>📚 参考：<a href="/FE-prepare-interview/直击概念/17ai/s_ai_11-pretraining_finetuning.html">预训练与微调</a> | <a href="/FE-prepare-interview/直击概念/17ai/s_ai_16-quantization.html">模型量化</a></p></blockquote><p><strong>场景</strong>：面试官问&quot;公司想定制一个客服模型，应该走预训练还是微调？LoRA 是什么？&quot;</p><p><strong>考察点</strong>：预训练与微调的区别、LoRA 原理、参数高效微调</p><details class="details custom-block"><summary>详细信息</summary><h2 id="核心回答" tabindex="-1">核心回答 <a class="header-anchor" href="#核心回答" aria-label="Permalink to &quot;核心回答&quot;">​</a></h2><p>大模型的训练分为两个阶段：</p><table><thead><tr><th>阶段</th><th style="text-align:center;">数据量</th><th style="text-align:center;">计算量</th><th>产出</th><th>类比</th></tr></thead><tbody><tr><td><strong>预训练</strong></td><td style="text-align:center;">海量（TB 级）</td><td style="text-align:center;">极大（万卡 GPU）</td><td>基座模型</td><td>通识教育（小学到大学）</td></tr><tr><td><strong>微调</strong></td><td style="text-align:center;">少量（KB/MB 级）</td><td style="text-align:center;">较小</td><td>领域模型</td><td>职业技能培训</td></tr></tbody></table><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>微调方式：</span></span>
<span class="line"><span>├── Full Fine-Tuning：更新全部参数（贵，需大量 GPU）</span></span>
<span class="line"><span>├── SFT（有监督微调）：用问答对训练，让模型学会&quot;对话&quot;</span></span>
<span class="line"><span>└── PEFT（参数高效微调）：只更新少量参数</span></span>
<span class="line"><span>    ├── LoRA：插入低秩矩阵，只训练这些小矩阵（最流行）</span></span>
<span class="line"><span>    └── QLoRA：LoRA + 量化，单张消费级 GPU 可微调 70B</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p><strong>LoRA 原理</strong>（简化）：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>原始权重矩阵 W 冻结，在旁边插入 A×B（低秩矩阵），只训练 A 和 B</span></span>
<span class="line"><span>原始输出: h = Wx</span></span>
<span class="line"><span>LoRA输出: h = Wx + ABx</span></span>
<span class="line"><span></span></span>
<span class="line"><span>优势：训练参数量减少 ~99%，内存需求降低 ~90%</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p><strong>前端不需要微调模型</strong>，但需要理解这个概念，因为：</p><ul><li>公司可能用 LoRA 微调私有模型做客服/代码审查</li><li>前端调用微调后的模型 API 做特定任务</li></ul><h2 id="面试回答要点" tabindex="-1">面试回答要点 <a class="header-anchor" href="#面试回答要点" aria-label="Permalink to &quot;面试回答要点&quot;">​</a></h2><ul><li>区分预训练（通识）和微调（专业）</li><li>知道 LoRA 是&quot;冻结大模型，只加小插件训练&quot;</li><li>能说出 QLoRA 让普通 GPU 也能微调大模型</li></ul></details><blockquote><p>来源：<a href="/FE-prepare-interview/直击概念/17ai/s_ai_11-pretraining_finetuning.html">预训练与微调概念讲解</a></p></blockquote>`,6)])])}const b=n(i,[["render",l]]);export{u as __pageData,b as default};
